features.snippet:
module Executor(
  input enum bit [1:0] {add, sub, mul} opcode,
  input [7:0] arg0, arg1,
  output [7:0] result
);
  assign result = opcode == add ? arg0 + arg1 : opcode == sub ? arg0 - arg1 : arg0 * arg1;
endmodule

struct packed {
  enum bit [0:0] {a, b} tag;
  union packed {
    logic [7:0] a;
    logic [15:0] b;
  } body;
} i;
